import{_ as e,o as l,c as d,ag as a}from"./chunks/framework.DTiDeF2Q.js";const g=JSON.parse('{"title":"פונקציות | Dotfiles (HE)","titleTemplate":":title","description":"פונקציות מעטפת המשפרות את חוויית הטרמינל שלך. כלים לבדיקת API, ניהול קבצים, פעולות מערכת ועוד. תואם ל-macOS, Linux ו-WSL דרך Dotfiles.","frontmatter":{"title":"פונקציות | Dotfiles","description":"פונקציות מעטפת המשפרות את חוויית הטרמינל שלך. כלים לבדיקת API, ניהול קבצים, פעולות מערכת ועוד. תואם ל-macOS, Linux ו-WSL דרך Dotfiles.","lang":"he-IL","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"פונקציות preview","canonical":"/he/functions/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"פונקציות","pageType":"docs","schemaType":"WebPage","metaTitle":"פונקציות - Dotfiles (IL)","permalink":"/he/functions/","meta":[{"name":"keywords","content":"functions, shell, bash, zsh, dotfiles, productivity, utilities, api, file, system"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"פונקציות מעטפת המשפרות את חוויית הטרמינל שלך. כלים לבדיקת API, ניהול קבצים, פעולות מערכת ועוד."},{"name":"twitter:title","content":"פונקציות - Dotfiles"},{"name":"og:title","content":"פונקציות - Dotfiles"},{"name":"og:description","content":"פונקציות מעטפת המשפרות את חוויית הטרמינל שלך. כלים לבדיקת API, ניהול קבצים, פעולות מערכת ועוד."},{"name":"og:image:alt","content":"Dotfiles - עוצב בפשטות להתאים לחיי המעטפת שלך"},{"name":"og:locale","content":"he_IL"}]},"headers":[],"relativePath":"he/functions/index.md","filePath":"he/functions/index.md","lastUpdated":1773010926000}'),i={name:"he/functions/index.md"};function o(s,t,n,c,r,f){return l(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="פונקציות" tabindex="-1">פונקציות <a class="header-anchor" href="#פונקציות" aria-label="Permalink to &quot;פונקציות&quot;">​</a></h1><p>כלי מעטפת לשיפור הפרודוקטיביות שלך ב-macOS, Linux ו-Windows.</p><h2 id="גלה" tabindex="-1">גלה <a class="header-anchor" href="#גלה" aria-label="Permalink to &quot;גלה&quot;">​</a></h2><p>פונקציות מוגדרות כקבצי <code>.sh</code> בודדים. במהלך <code>chezmoi apply</code>, הן מצורפות ל-<code>~/.config/shell/functions.sh</code> ונטענות על ידי המעטפת שלך.</p><h2 id="התחל" tabindex="-1">התחל <a class="header-anchor" href="#התחל" aria-label="Permalink to &quot;התחל&quot;">​</a></h2><h3 id="הוסף-פונקציה" tabindex="-1">הוסף פונקציה <a class="header-anchor" href="#הוסף-פונקציה" aria-label="Permalink to &quot;הוסף פונקציה&quot;">​</a></h3><ol><li>צור קובץ <code>.sh</code> חדש (למשל, <code>myfunc.sh</code>)</li><li>הוסף את הגדרת הפונקציה שלך</li><li>החל שינויים:<div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chezmoi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> apply</span></span></code></pre></div></li></ol><h2 id="הפניה" tabindex="-1">הפניה <a class="header-anchor" href="#הפניה" aria-label="Permalink to &quot;הפניה&quot;">​</a></h2><h3 id="בדיקת-api" tabindex="-1">בדיקת API <a class="header-anchor" href="#בדיקת-api" aria-label="Permalink to &quot;בדיקת API&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">פונקציה</th><th style="text-align:left;">תיאור</th><th style="text-align:left;">שימוש</th></tr></thead><tbody><tr><td style="text-align:left;"><code>apihealth</code></td><td style="text-align:left;">בדוק תקינות של API אחד או יותר</td><td style="text-align:left;"><code>apihealth [OPTIONS] URL [URL ...]</code></td></tr><tr><td style="text-align:left;"><code>apilatency</code></td><td style="text-align:left;">נטר זמן תגובה של API</td><td style="text-align:left;"><code>apilatency URL [COUNT] [INTERVAL]</code></td></tr><tr><td style="text-align:left;"><code>apiload</code></td><td style="text-align:left;">בצע בדיקת עומס בסיסית</td><td style="text-align:left;"><code>apiload URL [REQUESTS] [DELAY]</code></td></tr><tr><td style="text-align:left;"><code>httpdebug</code></td><td style="text-align:left;">דבג בקשות HTTP עם תזמון</td><td style="text-align:left;"><code>httpdebug [options] [url]</code></td></tr></tbody></table><h3 id="כלי-http" tabindex="-1">כלי HTTP <a class="header-anchor" href="#כלי-http" aria-label="Permalink to &quot;כלי HTTP&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">פונקציה</th><th style="text-align:left;">תיאור</th><th style="text-align:left;">שימוש</th></tr></thead><tbody><tr><td style="text-align:left;"><code>curlheader</code></td><td style="text-align:left;">הצג כותרות HTTP</td><td style="text-align:left;"><code>curlheader [header] [url]</code></td></tr><tr><td style="text-align:left;"><code>curlstatus</code></td><td style="text-align:left;">בדוק קוד סטטוס HTTP</td><td style="text-align:left;"><code>curlstatus [url]</code></td></tr><tr><td style="text-align:left;"><code>curltime</code></td><td style="text-align:left;">מדוד מדדי תזמון HTTP</td><td style="text-align:left;"><code>curltime [url]</code></td></tr><tr><td style="text-align:left;"><code>view-source</code></td><td style="text-align:left;">הצג קוד מקור של אתר</td><td style="text-align:left;"><code>view-source URL</code></td></tr><tr><td style="text-align:left;"><code>whoisport</code></td><td style="text-align:left;">מצא תהליך המשתמש בפורט</td><td style="text-align:left;"><code>whoisport PORT</code></td></tr></tbody></table><h3 id="ניהול-קבצים" tabindex="-1">ניהול קבצים <a class="header-anchor" href="#ניהול-קבצים" aria-label="Permalink to &quot;ניהול קבצים&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">פונקציה</th><th style="text-align:left;">תיאור</th><th style="text-align:left;">שימוש</th></tr></thead><tbody><tr><td style="text-align:left;"><code>backup</code></td><td style="text-align:left;">צור גיבויים עם חותמת זמן</td><td style="text-align:left;"><code>backup [--max-size SIZE] [--keep N] &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>encode64</code> / <code>decode64</code></td><td style="text-align:left;">קידוד ופענוח Base64</td><td style="text-align:left;"><code>encode64 &quot;string&quot;</code></td></tr><tr><td style="text-align:left;"><code>extract</code></td><td style="text-align:left;">חלץ פורמטי ארכיון</td><td style="text-align:left;"><code>extract [file]</code></td></tr><tr><td style="text-align:left;"><code>hexdump</code></td><td style="text-align:left;">הצג קובץ בפורמט hex</td><td style="text-align:left;"><code>hexdump [file] [lines]</code></td></tr><tr><td style="text-align:left;"><code>ren</code></td><td style="text-align:left;">שנה שמות סיומות באצווה</td><td style="text-align:left;"><code>ren OLD_EXT NEW_EXT</code></td></tr><tr><td style="text-align:left;"><code>size</code></td><td style="text-align:left;">בדוק גודל קובץ או תיקיה</td><td style="text-align:left;"><code>size [file/directory]</code></td></tr><tr><td style="text-align:left;"><code>zipf</code></td><td style="text-align:left;">צור ארכיוני ZIP</td><td style="text-align:left;"><code>zipf [folder]</code></td></tr></tbody></table><h3 id="שמות-קבצים" tabindex="-1">שמות קבצים <a class="header-anchor" href="#שמות-קבצים" aria-label="Permalink to &quot;שמות קבצים&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">פונקציה</th><th style="text-align:left;">תיאור</th><th style="text-align:left;">שימוש</th></tr></thead><tbody><tr><td style="text-align:left;"><code>kebabcase</code></td><td style="text-align:left;">המר ל-kebab-case</td><td style="text-align:left;"><code>kebabcase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>lowercase</code></td><td style="text-align:left;">המר לאותיות קטנות</td><td style="text-align:left;"><code>lowercase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>sentencecase</code></td><td style="text-align:left;">המר לאות ראשונה גדולה</td><td style="text-align:left;"><code>sentencecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>snakecase</code></td><td style="text-align:left;">המר ל-snake_case</td><td style="text-align:left;"><code>snakecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>titlecase</code></td><td style="text-align:left;">המר לכותרת</td><td style="text-align:left;"><code>titlecase &lt;files...&gt;</code></td></tr><tr><td style="text-align:left;"><code>uppercase</code></td><td style="text-align:left;">המר לאותיות גדולות</td><td style="text-align:left;"><code>uppercase &lt;files...&gt;</code></td></tr></tbody></table><h3 id="כלי-מערכת" tabindex="-1">כלי מערכת <a class="header-anchor" href="#כלי-מערכת" aria-label="Permalink to &quot;כלי מערכת&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">פונקציה</th><th style="text-align:left;">תיאור</th><th style="text-align:left;">שימוש</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine</code></td><td style="text-align:left;">מנע מהמערכת לישון</td><td style="text-align:left;"><code>caffeine [command]</code></td></tr><tr><td style="text-align:left;"><code>environment</code></td><td style="text-align:left;">זהה סביבת מערכת הפעלה</td><td style="text-align:left;"><code>environment</code></td></tr><tr><td style="text-align:left;"><code>freespace</code></td><td style="text-align:left;">נקה שטח דיסק פינוי</td><td style="text-align:left;"><code>freespace [disk]</code></td></tr><tr><td style="text-align:left;"><code>hiddenfiles</code></td><td style="text-align:left;">הפעל/כבה קבצים מוסתרים ב-Finder</td><td style="text-align:left;"><code>hiddenfiles [show|hide]</code></td></tr><tr><td style="text-align:left;"><code>hostinfo</code></td><td style="text-align:left;">הצג מידע על המארח</td><td style="text-align:left;"><code>hostinfo</code></td></tr><tr><td style="text-align:left;"><code>hstats</code></td><td style="text-align:left;">הצג סטטיסטיקות שימוש בפקודות</td><td style="text-align:left;"><code>hstats</code></td></tr><tr><td style="text-align:left;"><code>last</code></td><td style="text-align:left;">רשום קבצים ששונו לאחרונה</td><td style="text-align:left;"><code>last [minutes]</code></td></tr><tr><td style="text-align:left;"><code>logout</code></td><td style="text-align:left;">התנתקות חוצה פלטפורמות</td><td style="text-align:left;"><code>logout [--force]</code></td></tr><tr><td style="text-align:left;"><code>myproc</code></td><td style="text-align:left;">רשום תהליכי משתמש</td><td style="text-align:left;"><code>myproc</code></td></tr><tr><td style="text-align:left;"><code>stopwatch</code></td><td style="text-align:left;">שעון עצר בטרמינל</td><td style="text-align:left;"><code>stopwatch</code></td></tr><tr><td style="text-align:left;"><code>sysinfo</code></td><td style="text-align:left;">הצג מידע מערכת</td><td style="text-align:left;"><code>sysinfo</code></td></tr></tbody></table><h3 id="פקודות-caffeine" tabindex="-1">פקודות Caffeine <a class="header-anchor" href="#פקודות-caffeine" aria-label="Permalink to &quot;פקודות Caffeine&quot;">​</a></h3><p>מנע מהמערכת שלך לישון או להפעיל את שומר המסך.</p><table tabindex="0"><thead><tr><th style="text-align:left;">פקודה</th><th style="text-align:left;">תיאור</th></tr></thead><tbody><tr><td style="text-align:left;"><code>caffeine daemon</code></td><td style="text-align:left;">הפעל את שירות caffeine</td></tr><tr><td style="text-align:left;"><code>caffeine status</code></td><td style="text-align:left;">בדוק אם השירות פועל</td></tr><tr><td style="text-align:left;"><code>caffeine start</code></td><td style="text-align:left;">שמור על המסך ער</td></tr><tr><td style="text-align:left;"><code>caffeine stop</code></td><td style="text-align:left;">אפשר למסך לישון</td></tr><tr><td style="text-align:left;"><code>caffeine toggle</code></td><td style="text-align:left;">החלף מצב ערות מסך</td></tr><tr><td style="text-align:left;"><code>caffeine shutdown</code></td><td style="text-align:left;">כבה את השירות</td></tr></tbody></table><p>עובד ב-macOS (<code>caffeinate</code> מקורי), Linux (<code>xdg-screensaver</code>), ו-Windows (PowerShell).</p><h3 id="אבטחה" tabindex="-1">אבטחה <a class="header-anchor" href="#אבטחה" aria-label="Permalink to &quot;אבטחה&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">פונקציה</th><th style="text-align:left;">תיאור</th><th style="text-align:left;">שימוש</th></tr></thead><tbody><tr><td style="text-align:left;"><code>genpass</code></td><td style="text-align:left;">צור סיסמאות חזקות</td><td style="text-align:left;"><code>genpass [num_blocks] [separator]</code></td></tr><tr><td style="text-align:left;"><code>keygen</code></td><td style="text-align:left;">צור זוגות מפתחות SSH</td><td style="text-align:left;"><code>keygen [name] [email] [type] [bits]</code></td></tr></tbody></table><h3 id="ניווט" tabindex="-1">ניווט <a class="header-anchor" href="#ניווט" aria-label="Permalink to &quot;ניווט&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">פונקציה</th><th style="text-align:left;">תיאור</th><th style="text-align:left;">שימוש</th></tr></thead><tbody><tr><td style="text-align:left;"><code>cdls</code></td><td style="text-align:left;">החלף תיקיה והצג רשימה</td><td style="text-align:left;"><code>cdls [directory]</code></td></tr><tr><td style="text-align:left;"><code>goto</code></td><td style="text-align:left;">ניווט מהיר לתיקיה</td><td style="text-align:left;"><code>goto [directory]</code></td></tr><tr><td style="text-align:left;"><code>mount_read_only</code></td><td style="text-align:left;">טען קריאה-בלבד ככתיבה-קריאה</td><td style="text-align:left;"><code>mount_read_only [image]</code></td></tr><tr><td style="text-align:left;"><code>rd</code></td><td style="text-align:left;">הסר תיקיה</td><td style="text-align:left;"><code>rd [directory]</code></td></tr><tr><td style="text-align:left;"><code>remove_disk</code></td><td style="text-align:left;">הוצא דיסק בבטחה</td><td style="text-align:left;"><code>remove_disk [disk]</code></td></tr></tbody></table><h3 id="שונות" tabindex="-1">שונות <a class="header-anchor" href="#שונות" aria-label="Permalink to &quot;שונות&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">פונקציה</th><th style="text-align:left;">תיאור</th><th style="text-align:left;">שימוש</th></tr></thead><tbody><tr><td style="text-align:left;"><code>matrix</code></td><td style="text-align:left;">אפקטי Matrix בטרמינל</td><td style="text-align:left;"><code>matrix [options]</code></td></tr><tr><td style="text-align:left;"><code>prependpath</code></td><td style="text-align:left;">הוסף תיקיה ל-PATH</td><td style="text-align:left;"><code>prependpath [directory]</code></td></tr><tr><td style="text-align:left;"><code>ql</code></td><td style="text-align:left;">פתח ב-Quick Look של macOS</td><td style="text-align:left;"><code>ql [file]</code></td></tr><tr><td style="text-align:left;"><code>vscode</code></td><td style="text-align:left;">פתח ב-VS Code</td><td style="text-align:left;"><code>vscode [file]</code></td></tr></tbody></table><h2 id="תאימות" tabindex="-1">תאימות <a class="header-anchor" href="#תאימות" aria-label="Permalink to &quot;תאימות&quot;">​</a></h2><ul><li><strong>macOS</strong> - תמיכה מלאה עם כלים ספציפיים ל-macOS</li><li><strong>Linux</strong> - תואם להפצות נפוצות</li><li><strong>Windows</strong> - תמיכה דרך WSL, Cygwin, או Git Bash</li></ul><h2 id="עזרה" tabindex="-1">עזרה <a class="header-anchor" href="#עזרה" aria-label="Permalink to &quot;עזרה&quot;">​</a></h2><p>כל פונקציה כוללת תיעוד דרך <code>--help</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">apihealth</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --help</span></span></code></pre></div>',33)])])}const y=e(i,[["render",o]]);export{g as __pageData,y as default};
